package com.recettealarm.app;
import android.app.*;import android.content.*;import android.database.*;import android.graphics.Typeface;import android.os.*;import android.view.*;import android.widget.*;import java.util.*;
public class CookingActivity extends Activity{DB db;ArrayList<long[]> ids=new ArrayList<>();ArrayList<String[]> txt=new ArrayList<>();int idx=0;TextView desc,note,stepTitle,tempView;TimerRingView ring;CountDownTimer cd;long rid,totalMs=0,remainingMs=0;boolean running=false;public void onCreate(Bundle b){super.onCreate(b);getWindow().addFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON);db=new DB(this);rid=getIntent().getLongExtra("id",0);Cursor c=db.steps(rid);while(c.moveToNext()){ids.add(new long[]{c.getLong(0),c.getInt(4),c.getInt(7)});txt.add(new String[]{c.getString(3),c.getString(6),c.getString(8)});}c.close();draw();}
 void draw(){LinearLayout r=UI.root(this);Button back=UI.whiteBtn(this,"← Retour recette");r.addView(back);back.setOnClickListener(v->{cancelTimer();finish();});r.addView(UI.center(this,"Mode Cuisine",26,Typeface.BOLD));stepTitle=UI.center(this,"",16,Typeface.NORMAL);r.addView(stepTitle);LinearLayout box=UI.section(this);ring=new TimerRingView(this);box.addView(ring,new LinearLayout.LayoutParams(-1,UI.dp(this,260)));tempView=UI.center(this,"",16,Typeface.BOLD);box.addView(tempView);box.addView(UI.center(this,"Anti-Brûlure : sonnerie + vibration + plein écran",14,Typeface.NORMAL));r.addView(box);desc=UI.tv(this,"",23,Typeface.BOLD);note=UI.tv(this,"",17,Typeface.BOLD);note.setTextColor(UI.danger);r.addView(desc);r.addView(note);LinearLayout controls=UI.row(this);Button pause=UI.whiteBtn(this,"⏸");Button start=UI.limeBtn(this,"▶");Button plus=UI.whiteBtn(this,"+5");controls.addView(pause,new LinearLayout.LayoutParams(0,-2,1));controls.addView(start,new LinearLayout.LayoutParams(0,-2,1));controls.addView(plus,new LinearLayout.LayoutParams(0,-2,1));r.addView(controls);Button next=UI.btn(this,"✓ Étape suivante");r.addView(next);r.addView(UI.muted(this,"L'écran reste allumé pendant la cuisson.",13));start.setOnClickListener(v->startStep(remainingMs>0?remainingMs:getCurrentMs(),true));pause.setOnClickListener(v->pauseTimer());plus.setOnClickListener(v->startStep((remainingMs>0?remainingMs:0)+5*60_000L,true));next.setOnClickListener(v->nextStep());showStep();}
 long getCurrentMs(){if(ids.size()==0)return 0;return Math.max(1,ids.get(idx)[1])*60_000L;}void showStep(){cancelTimer();if(ids.size()==0){stepTitle.setText("Aucune étape");desc.setText("Ajoute des étapes dans Modifier / Admin");note.setText("");renderTime(0,1);return;}totalMs=getCurrentMs();remainingMs=totalMs;stepTitle.setText("Étape "+(idx+1)+" / "+ids.size());desc.setText(txt.get(idx)[0]);note.setText("⚠ "+safe(txt.get(idx)[1]));tempView.setText(ids.get(idx)[2]>0?"🌡 "+ids.get(idx)[2]+"°C":"🌡 Température non définie");renderTime(remainingMs,totalMs);}void startStep(long ms,boolean schedule){if(ids.size()==0)return;cancelTimer();remainingMs=ms;running=true;if(totalMs<=0)totalMs=ms;if(schedule)AlarmReceiver.schedule(this,ms,safe(txt.get(idx)[1]),"Étape "+(idx+1)+" terminée");cd=new CountDownTimer(ms,500){public void onTick(long m){remainingMs=m;renderTime(m,totalMs);}public void onFinish(){remainingMs=0;running=false;renderTime(0,totalMs);openAlarmNow();}}.start();}
 void openAlarmNow(){AlarmReceiver.cancel(this);startActivity(new Intent(this,AlarmActivity.class).putExtra("note",safe(txt.get(idx)[1])).putExtra("title","Étape "+(idx+1)+" terminée !"));}void pauseTimer(){if(cd!=null)cd.cancel();AlarmReceiver.cancel(this);running=false;UI.toast(this,"Timer en pause");}void cancelTimer(){if(cd!=null)cd.cancel();AlarmReceiver.cancel(this);running=false;}void nextStep(){cancelTimer();idx++;if(idx>=ids.size()){UI.toast(this,"Recette terminée ✅");finish();}else showStep();}void renderTime(long m,long total){String t=String.format(Locale.FRANCE,"%02d:%02d",m/60000,(m/1000)%60);float p=total<=0?0:(float)m/(float)total;if(ring!=null)ring.setTimer(t,p);}String safe(String s){return s==null||s.trim().isEmpty()?"Vérifie la cuisson, remue le plat et baisse le feu si besoin.":s;}}
